## Implementation
```typescript
export class GateMachine {
  constructor(private db: Database.Database) {}

  currentPhase(runId: number): Phase {
    const run = db.prepare('SELECT phase FROM flywheel_runs WHERE id=?').get(runId) as any;
    return run?.phase ?? Phase.INIT;
  }

  isGate(phase: Phase): boolean {
    return phase.startsWith('gate_');
  }

  advance(runId: number, actor = 'human'): Phase {
    const current = this.currentPhase(runId);
    const next = TRANSITIONS[current];
    if (!next) throw new Error(`Phase ${current} has no next state`);

    // Atomic: event + state update in one transaction
    db.transaction(() => {
      eventLog.append(runId, 'phase_transition', current, next, actor, {});
      db.prepare('UPDATE flywheel_runs SET phase=? WHERE id=?').run(next, runId);
    })();

    console.log(chalk.green(`✓ Advanced: ${current} → ${next}`));
    return next;
  }

  async waitForGate(runId: number, signal: AbortSignal): Promise<void> {
    while (!signal.aborted) {
      const phase = this.currentPhase(runId);
      if (!this.isGate(phase)) return;  // gate opened
      await sleep(5_000);  // poll every 5s
    }
  }
}
```

