## Class API
```typescript
export class PromptEngine {
  constructor(
    private prompts: Record<string, Prompt>,
    private db: Database.Database,
    private ntm: NtmBridge,
    private sshConfig: SshConfig
  ) {}

  // Resolve {variable} substitutions
  resolve(name: string, vars?: Record<string, string>): string {
    const prompt = this.prompts[name];
    if (!prompt) throw new Error(\`Unknown prompt: \${name}. Did you mean: \${this.suggest(name)}?\`);
    let text = prompt.text;
    // Priority 1: explicit vars
    // Priority 2: run context from DB
    // Priority 3: VPS env vars
    text = text.replace(/\{(\w+)\}/g, (match, varName) => {
      if (vars?.[varName]) return vars[varName];
      const runVal = this.getRunContextVar(varName);
      if (runVal) return runVal;
      const envVal = this.getEnvVar(varName);
      if (envVal) return envVal;
      console.warn(\`Unresolved variable: \${match} in prompt \${name}\`);
      return match;
    });
    return text;
  }

  // Send prompt to agent(s) via NTM
  async send(name: string, target: SendTarget, vars?: Record<string, string>): Promise<NtmSendResult> {
    const resolved = this.resolve(name, vars);
    const session = this.getCurrentSession();
    const result = await this.ntm.send(session, resolved, target);
    this.logSend(name, target, result);
    return result;
  }

  // List prompts with optional phase filter
  list(filter?: { phase?: string }): Array<{ name: string } & Prompt> {
    return Object.entries(this.prompts)
      .filter(([_, p]) => !filter?.phase || p.phase === filter.phase)
      .map(([name, p]) => ({ name, ...p }));
  }

  // Fuzzy suggest for typos
  private suggest(name: string): string { ... }

  // Get variable from current run context
  private getRunContextVar(name: string): string | undefined { ... }

  // Get variable from VPS config
  private getEnvVar(name: string): string | undefined {
    if (name === 'project_path') return this.sshConfig.remote_repo_root;
    return undefined;
  }

  // Log to prompt_sends table
  private logSend(name: string, target: SendTarget, result: NtmSendResult): void { ... }
}
```

## Fuzzy Suggestion
When a prompt name is not found, suggest the closest match using simple
Levenshtein distance or prefix matching. This helps with typos:
"Did you mean: fresh-review?"

## Acceptance Criteria
- resolve() substitutes variables from all 3 priority sources
- send() calls NtmBridge.send() and logs to prompt_sends
- list() returns all prompts, optionally filtered by phase
- Unknown prompt → error with fuzzy suggestion
- Unresolved variable → warning (not error), left as-is

